// Package cefapi defines the generated CEF ABI contract shared by generation and loading.
package cefapi

const (
	// Version is the only CEF API version represented by these bindings.
	Version = 15000
	// LinuxHash is CEF_API_HASH_15000 for OS_LINUX from cef_api_versions.h.
	LinuxHash = "210767725a6feb2e4becd3956b648cab6a006712"
	// MinimumMajor is the minimum Chrome/CEF runtime major for this contract.
	MinimumMajor = 150
)
